88	        /// </summary>
89	        internal MudSelect<T>? MudSelect => (MudSelect<T>?)IMudSelect;
90	
91	        /// <summary>
92	        /// The custom value associated with this item.
93	        /// </summary>
94	        [Parameter]
95	        [Category(CategoryTypes.FormComponent.Behavior)]
96	        public T? Value { get; set; }
97	
98	        /// <summary>
99	        /// Prevents the user from interacting with this item.
100	        /// </summary>
101	        /// <remarks>
102	        /// Defaults to <c>false</c>.
103	        /// </remarks>
104	        [Parameter]
105	        [Category(CategoryTypes.General.Behavior)]
106	        public bool Disabled { get; set; }
