    /// <summary>
    /// Compares <see cref="NullableObject{T}"/> instances using a custom element-level comparer.
    /// </summary>
    /// <typeparam name="TItem">The type of the wrapped items.</typeparam>
    private sealed class NullableObjectComparer<TItem>(IEqualityComparer<TItem>? comparer) : IEqualityComparer<NullableObject<TItem>>
    {
        private readonly IEqualityComparer<TItem> _comparer = comparer ?? EqualityComparer<TItem>.Default;

        public bool Equals(NullableObject<TItem> x, NullableObject<TItem> y)
        {
            if (x.IsNull)
            {
                return y.IsNull;
            }

            if (y.IsNull)
            {
                return false;
            }

            return _comparer.Equals(x.Item, y.Item);
        }

        public int GetHashCode(NullableObject<TItem> obj)
        {
            return obj.IsNull
                ? 0
                : _comparer.GetHashCode(obj.Item!);
        }
    }
}

