    private HashSet<string> _selectedValues = new HashSet<string>() {"test1"};

    private void SelectedValuesChanged(IReadOnlyCollection<string?>? newSelectedValues)
    {
        _selectedValues.Clear();
        foreach (var item in newSelectedValues)
        {
            _selectedValues.Add(item);
        }
